import{_ as t,c as a,o as n,ag as o}from"./chunks/framework.S-Qvb3wi.js";const u=JSON.parse('{"title":"x402","description":"","frontmatter":{"title":"x402","aside":false,"outline":false},"headers":[],"relativePath":"x402.md","filePath":"x402.md"}'),i={name:"x402.md"};function r(s,e,l,c,d,p){return n(),a("div",null,e[0]||(e[0]=[o('<h1 id="x402-api" tabindex="-1">x402 API <a class="header-anchor" href="#x402-api" aria-label="Permalink to &quot;x402 API&quot;">​</a></h1><p><strong>DGrid x402 API</strong> is DGrid&#39;s pay-per-inference access mode for AI models. Instead of creating an account, pre-funding a balance, or managing separate billing flows, developers and autonomous agents can pay LLM inference costs directly through the <strong>x402 payment protocol</strong> as part of the API request lifecycle.</p><p>This makes x402 especially useful for:</p><ul><li><strong>Agents and autonomous workflows</strong> that need to call an LLM and settle payment immediately</li><li><strong>Server-side tools and scripts</strong> that should avoid account provisioning and manual top-ups</li><li><strong>On-demand integrations</strong> where the simplest path is &quot;request inference, authorize payment, receive the result&quot;</li></ul><h2 id="why-x402-api-matters" tabindex="-1">Why x402 API Matters <a class="header-anchor" href="#why-x402-api-matters" aria-label="Permalink to &quot;Why x402 API Matters&quot;">​</a></h2><p>Traditional AI billing usually requires:</p><ul><li>Creating an account with the provider</li><li>Funding a prepaid balance or attaching a billing method</li><li>Managing API keys, quotas, and billing dashboards</li></ul><p>With x402 on DGrid, the flow becomes much more direct:</p><blockquote><p>Request inference → receive payment requirements → sign once → submit payment and inference together</p></blockquote><p>For agentic systems, this is a major simplification. The same runtime that decides to use a model can also authorize and settle the cost of that inference call, without switching into a separate account-management workflow.</p><h2 id="primary-use-case-agents-paying-for-inference" tabindex="-1">Primary Use Case: Agents Paying for Inference <a class="header-anchor" href="#primary-use-case-agents-paying-for-inference" aria-label="Permalink to &quot;Primary Use Case: Agents Paying for Inference&quot;">​</a></h2><p>x402 is designed for the case where an <strong>agent</strong> needs to:</p><ol><li>Choose a model</li><li>Call the model API</li><li>Pay the inference fee</li><li>Continue execution with the result</li></ol><p>This is valuable for:</p><ul><li>AI agents operating in backend workflows</li><li>Web3 agents or protocols that want payment-aware inference</li><li>Multi-step automations that should treat inference as a directly payable resource</li></ul><h2 id="how-the-flow-works" tabindex="-1">How the Flow Works <a class="header-anchor" href="#how-the-flow-works" aria-label="Permalink to &quot;How the Flow Works&quot;">​</a></h2><p>x402 on DGrid uses a <strong>two-step request flow</strong>:</p><ol><li><strong>Initial request without <code>x-payment</code></strong> The server returns <code>402 Payment Required</code> plus signable payment requirements.</li><li><strong>Client signs and retries</strong> The client generates the <code>x-payment</code> payload and sends the same inference request again with the payment header.</li></ol><p>This pattern keeps payment authorization explicit while still letting the inference call remain simple and automatable.</p><h2 id="supported-payment-asset" tabindex="-1">Supported Payment Asset <a class="header-anchor" href="#supported-payment-asset" aria-label="Permalink to &quot;Supported Payment Asset&quot;">​</a></h2><p>The current x402 endpoint uses:</p><ul><li><strong>Protocol</strong>: x402</li><li><strong>Network</strong>: <code>eip155:56</code> (BSC)</li><li><strong>Payment token</strong>: <code>USD1</code></li><li><strong>Asset contract</strong>: <code>0x8d0D000Ee44948FC98c9B98A4FA4921476f08B0d</code></li></ul><h2 id="api-reference" tabindex="-1">API Reference <a class="header-anchor" href="#api-reference" aria-label="Permalink to &quot;API Reference&quot;">​</a></h2><p>The endpoint-level reference has been moved to the dedicated <a href="/x402-api-reference">API Reference</a> subpage under x402 API.</p><p>The x402-specific part is the <strong>payment handshake</strong>: first request the endpoint, receive <code>402 Payment Required</code>, then retry the same inference call with a signed <code>x-payment</code> header.</p><p>For model invocation patterns, payload conventions, and provider-specific examples, you can also reuse the DGrid <strong>Model API</strong> references:</p><ul><li><a href="/Model-API-Chat#chat-completions">OpenAI-compatible Chat Completions</a></li><li><a href="/Model-API-Chat#native-claude-format">Claude-compatible Messages API</a></li></ul><p>Those pages cover the standard OpenAI-style and Claude-style request formats. The x402 reference page focuses on the payment-specific wrapper and the shared inference fields used by the x402 endpoint.</p><h2 id="operational-notes" tabindex="-1">Operational Notes <a class="header-anchor" href="#operational-notes" aria-label="Permalink to &quot;Operational Notes&quot;">​</a></h2><p>After successful settlement, the service records payment logs into the <code>x402_payment_logs</code> table on the backend.</p><h2 id="when-to-use-x402-vs-ai-gateway" tabindex="-1">When to Use x402 vs AI Gateway <a class="header-anchor" href="#when-to-use-x402-vs-ai-gateway" aria-label="Permalink to &quot;When to Use x402 vs AI Gateway&quot;">​</a></h2><p>Use <strong>AI Gateway</strong> when you want:</p><ul><li>classic API-key access</li><li>unified account-based model routing</li><li>long-running product integrations with standard billing workflows</li></ul><p>Use <strong>x402</strong> when you want:</p><ul><li>direct per-request payment</li><li>no pre-funded account balance</li><li>agent-friendly inference plus payment in one flow</li></ul>',35)]))}const m=t(i,[["render",r]]);export{u as __pageData,m as default};
